import {ref,custom} from "@hoge1e3/ref";
export function main(){
  const x=ref(3);
  const c=custom(
    ()=>x.value, (_)=>x.value=_);
  c.on("change",(e)=>
  console.log("c",e));
  x.on("change",(e)=>
  console.log("x",e));
  this.echo(c.value);
  c.value=5;
  this.echo(c.value);
  this.echo(x.value);
  
}